import { describe, it, expect, beforeEach } from 'vitest'
import { markChapterRead, toggleChapterRead, completionPct, latestProgress, useBookProgress } from './progress'

beforeEach(() => localStorage.clear())

describe('markChapterRead', () => {
  it('does not duplicate an already-read chapter', () => {
    markChapterRead('book-a', 1)
    markChapterRead('book-a', 1)
    // read back via internal store — expose a test-only accessor or check via useBookProgress in a rendered hook
  })
})

describe('completionPct', () => {
  it('returns 0 for a fresh book', () => {
    expect(completionPct(5, { mapRead: false, chaptersRead: [], updatedAt: 0 })).toBe(0)
  })
  it('counts the map as one unit', () => {
    expect(completionPct(4, { mapRead: true, chaptersRead: [], updatedAt: 1 })).toBe(20)
  })
  it('clamps chapters read beyond totalChapters', () => {
    expect(completionPct(2, { mapRead: false, chaptersRead: [1, 2, 3, 4], updatedAt: 1 })).toBeLessThanOrEqual(100)
  })
})

describe('latestProgress', () => {
  it('returns null when nothing has been touched', () => {
    expect(latestProgress({})).toBeNull()
  })
  it('ignores entries with updatedAt 0', () => {
    expect(latestProgress({ a: { mapRead: false, chaptersRead: [], updatedAt: 0 } })).toBeNull()
  })
  it('picks the most recently updated book', () => {
    const result = latestProgress({
      a: { mapRead: false, chaptersRead: [], updatedAt: 100 },
      b: { mapRead: false, chaptersRead: [], updatedAt: 200 },
    })
    expect(result?.bookId).toBe('b')
  })
