Completely untested, and it's the persistence backbone for prefs + progress.

**Edge cases:**
- Corrupt JSON in `localStorage` → falls back to `fallback` silently.
- `localStorage.setItem` throwing (private browsing / quota exceeded) — state still updates in-memory, listeners still fire.
- `subscribe`/unsubscribe correctness (listener not called after unsubscribing).
- Partial stored object merges with `fallback` (missing keys retained from default).

```ts
// src/lib/store.test.ts
import { describe, it, expect, vi, beforeEach } from 'vitest'
import { createLocalStore } from './store'

beforeEach(() => localStorage.clear())

describe('createLocalStore', () => {
  it('falls back to default on corrupt JSON', () => {
    localStorage.setItem('k', 'not json{')
    const store = createLocalStore('k', { a: 1 })
    expect(store.get()).toEqual({ a: 1 })
  })

  it('merges partial persisted state with fallback', () => {
    localStorage.setItem('k2', JSON.stringify({ a: 2 }))
    const store = createLocalStore('k2', { a: 1, b: 'x' })
    expect(store.get()).toEqual({ a: 2, b: 'x' })
  })

  it('keeps working in-memory if localStorage.setItem throws', () => {
    const store = createLocalStore('k3', { a: 1 })
    vi.spyOn(Storage.prototype, 'setItem').mockImplementation(() => {
      throw new Error('quota exceeded')
    })
    expect(() => store.set({ a: 2 })).not.toThrow()
    expect(store.get()).toEqual({ a: 2 })
  })

  it('notifies subscribers and respects unsubscribe', () => {
    const store = createLocalStore('k4', { a: 1 })
    const listener = vi.fn()
    const unsub = store.subscribe(listener)
    store.set({ a: 2 })
    expect(listener).toHaveBeenCalledTimes(1)
    unsub()
    store.set({ a: 3 })
    expect(listener).toHaveBeenCalledTimes(1)
  })
})
```

